import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { CheckCircle, TrendingUp } from 'lucide-react';
import './ValidationChart.css';

function ValidationChart({ apiUrl, simulationData }) {
  const [loading, setLoading] = useState(false);

  // If no simulation data provided, show empty state
  if (!simulationData) {
    return (
      <div className="validation-chart">
        <div className="card">
          <h2 className="card-title">Validation Results</h2>
          <p className="subtitle">
            Run a simulation first to see validation metrics comparing the digital twin's predictions.
          </p>
        </div>
      </div>
    );
  }

  // Calculate validation metrics from simulation data
  const calculateValidation = () => {
    // Extract metrics from simulation data
    const avgServiceTimes = simulationData.avg_service_time || {};
    const avgWaitingTimes = simulationData.avg_waiting_time || {};

    // Create chart data (showing twin results)
    const chartData = Object.keys(avgServiceTimes).map(station => ({
      name: station,
      Twin: avgServiceTimes[station]
    }));

    // Calculate summary
    const totalStations = Object.keys(avgServiceTimes).length;
    const avgProcessingTime = Object.values(avgServiceTimes).reduce((a, b) => a + b, 0) / totalStations;

    return {
      chartData,
      totalStations,
      avgProcessingTime,
      totalJobs: simulationData.total_jobs,
      totalTime: simulationData.total_time
    };
  };

  const validation = calculateValidation();

  return (
    <div className="validation-chart">
      <div className="card validation-header">
        <div className="accuracy-badge-large">
          <CheckCircle size={48} />
          <div>
            <div className="accuracy-value">Simulation Complete</div>
            <div className="accuracy-label">Digital Twin Results</div>
          </div>
        </div>
        <div className="validation-stats">
          <div className="stat-item">
            <span className="stat-label">Total Jobs</span>
            <span className="stat-value">{validation.totalJobs}</span>
          </div>
          <div className="stat-item">
            <span className="stat-label">Stations Simulated</span>
            <span className="stat-value">{validation.totalStations}</span>
          </div>
          <div className="stat-item">
            <span className="stat-label">Total Time</span>
            <span className="stat-value">{validation.totalTime.toFixed(0)}s</span>
          </div>
        </div>
      </div>

      <div className="card">
        <h2 className="card-title">Digital Twin Performance</h2>
        <p className="subtitle">
          Mean processing times by station as predicted by the digital twin simulation.
        </p>

        <ResponsiveContainer width="100%" height={400}>
          <BarChart data={validation.chartData} margin={{ top: 20, right: 30, left: 20, bottom: 60 }}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis
              dataKey="name"
              angle={-45}
              textAnchor="end"
              height={100}
              style={{ fontSize: '0.85rem' }}
            />
            <YAxis
              label={{ value: 'Mean Processing Time (s)', angle: -90, position: 'insideLeft' }}
              style={{ fontSize: '0.85rem' }}
            />
            <Tooltip
              contentStyle={{
                background: 'rgba(255, 255, 255, 0.95)',
                border: '2px solid #667eea',
                borderRadius: '8px'
              }}
            />
            <Legend
              wrapperStyle={{ paddingTop: '20px' }}
            />
            <Bar dataKey="Twin" fill="#55a868" name="Digital Twin Prediction" />
          </BarChart>
        </ResponsiveContainer>
      </div>

      <div className="card">
        <h3>Station-by-Station Results</h3>
        <div className="error-table">
          <div className="table-header">
            <div>Station</div>
            <div>Avg Time (s)</div>
            <div>Waiting (s)</div>
          </div>
          {Object.keys(simulationData.avg_service_time).map((station, idx) => (
            <div key={idx} className="table-row">
              <div className="station-name">{station}</div>
              <div>{simulationData.avg_service_time[station].toFixed(2)}</div>
              <div>{(simulationData.avg_waiting_time[station] || 0).toFixed(2)}</div>
            </div>
          ))}
        </div>
      </div>

      <div className="card methodology-card">
        <h3>About This Simulation</h3>
        <div className="methodology-content">
          <p>
            <strong>System Discovered:</strong> The digital twin automatically inferred the topology 
            and fitted statistical distributions to each station based on your uploaded production log.
          </p>
          <p>
            <strong>Simulation Method:</strong> SimPy discrete-event simulation using the discovered 
            distributions to generate realistic processing times.
          </p>
          <p>
            <strong>Results:</strong> These metrics show how the discovered digital twin performs, 
            including bottleneck identification (longest processing times) and flow characteristics.
          </p>
        </div>
      </div>
    </div>
  );
}

export default ValidationChart;
